// src/action.ts
async function run() {
  try {
    const targetPath = getInput("targetPath") || ".";
    const failOn = getInput("fail-on") || "high";
    const format2 = getInput("format") || "terminal";
    const resolvedPath = path23.resolve(process.env.GITHUB_WORKSPACE || process.cwd(), targetPath);
    const config = loadConfig(resolvedPath);
    const cacheKey = `securox-bins-${TOOLS_VERSION.opengrep}-${TOOLS_VERSION.trivy}-${TOOLS_VERSION.gitleaks}-${process.platform}-${process.arch}`;
    const cachePaths = [BIN_DIR];
    let cacheHit = false;
    try {
      const restoredKey = await restoreCache(cachePaths, cacheKey);
      if (restoredKey) {
        info(`✅ Restored securox binaries from cache: ${restoredKey}`);
        cacheHit = true;
      }
    } catch (e) {
      info(`⚠️ Cache restore failed or unavailable: ${e.message}`);
    }
    if (!cacheHit || !fs16.existsSync(BIN_DIR) || fs16.readdirSync(BIN_DIR).length === 0) {
      info("⏬ Binaries not found in cache. Downloading fresh copies...");
      await downloadAll();
      try {
        await saveCache2(cachePaths, cacheKey);
        info(`\uD83D\uDCBE Saved downloaded binaries to cache: ${cacheKey}`);
      } catch (e) {
        info(`⚠️ Cache save failed (non-fatal): ${e.message}`);
      }
    }
    const allFindings = [];
    if (config.scanners.sast) {
      startGroup("SAST Scan (Opengrep)");
      const sast = await runSAST(resolvedPath);
      allFindings.push(...sast);
      endGroup();
    }
    if (config.scanners.sca) {
      startGroup("SCA Scan (Trivy)");
      const sca = await runSCA(resolvedPath);
      allFindings.push(...sca);
      endGroup();
    }
    if (config.scanners.secrets) {
      startGroup("Secrets Scan (Gitleaks)");
      const secrets = await runSecrets(resolvedPath);
      allFindings.push(...secrets);
      endGroup();
    }
    if (config.scanners.performance) {
      startGroup("Performance Scan (Bearer)");
      const perf = await runPerformance(resolvedPath);
      allFindings.push(...perf);
      endGroup();
    }
    info("✅ Scanning completed!");
    switch (format2) {
      case "json":
        reportToJson(allFindings);
        break;
      case "sarif":
        reportToSarif(allFindings);
        break;
      case "terminal":
      default:
        reportToTerminal(allFindings);
    }
    const threshold = (failOn || config["severity-threshold"]).toLowerCase();
    if (threshold !== "none") {
      const severityOrder = { low: 1, medium: 2, high: 3, critical: 4 };
      const thresholdLvl = severityOrder[threshold] || 3;
      const fails = allFindings.some((f) => (severityOrder[f.severity] || 0) >= thresholdLvl);
      if (fails) {
        setFailed(`Securox failed: Found vulnerabilities >= ${threshold.toUpperCase()}`);
      }
    }
  } catch (error2) {
    setFailed(`Action execution failed: ${error2.message}`);
  }
}
run();
